#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=8e4+5;
int a[maxn],f[maxn],ans;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int n;
	cin>>n;
	stack<int> sta;
	for(int i=1; i<=n; i++) {
		cin>>a[i];
		while(!sta.empty()&&a[i]>=a[sta.top()]) {
			f[sta.top()]=i;
			sta.pop();
		}
		sta.push(i);
	}
	while(!sta.empty()) {
		f[sta.top()]=n+1;
		sta.pop();
	}
	for(int i=1; i<=n; i++) {
		if(f[i])
			ans+=f[i]-i-1;;
	}
	cout<<ans;
	return 0;
}
